import React, { useState, useEffect } from 'react';
import { FaExclamationTriangle, FaTimes, FaTrash, FaInfoCircle } from 'react-icons/fa';
import { syncAPI } from '../services/api';

function DeleteConfirmation({ employee, onClose, onConfirm }) {
  const [loading, setLoading] = useState(true);
  const [validation, setValidation] = useState(null);
  const [cascadeDelete, setCascadeDelete] = useState(false);

  useEffect(() => {
    const validateDeletion = async () => {
      try {
        const response = await syncAPI.validateDeletion(employee.EmployeeID);
        setValidation(response.data);
      } catch (error) {
        console.error('Validation failed:', error);
      } finally {
        setLoading(false);
      }
    };

    validateDeletion();
  }, [employee.EmployeeID]);

  const handleConfirm = () => {
    onConfirm(cascadeDelete);
  };

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal" onClick={(e) => e.stopPropagation()}>
        <div className="modal-header">
          <h3>
            <FaExclamationTriangle style={{ color: '#dd6b20', marginRight: '8px' }} />
            Delete Employee
          </h3>
          <button className="modal-close" onClick={onClose}>
            <FaTimes />
          </button>
        </div>

        <div className="modal-body">
          {loading ? (
            <div className="loading">
              <div className="spinner"></div>
            </div>
          ) : (
            <>
              <p style={{ marginBottom: '16px' }}>
                Are you sure you want to delete <strong>{employee.FullName}</strong> (ID: {employee.EmployeeID})?
              </p>

              {validation?.blocking_reasons?.length > 0 && (
                <div className="alert alert-danger">
                  <FaExclamationTriangle />
                  <div>
                    <strong>Cannot Delete:</strong>
                    <ul style={{ marginTop: '8px', paddingLeft: '20px' }}>
                      {validation.blocking_reasons.map((reason, index) => (
                        <li key={index}>{reason}</li>
                      ))}
                    </ul>
                  </div>
                </div>
              )}

              {validation?.warnings?.length > 0 && (
                <div className="alert alert-warning">
                  <FaInfoCircle />
                  <div>
                    <strong>Warnings:</strong>
                    <ul style={{ marginTop: '8px', paddingLeft: '20px' }}>
                      {validation.warnings.map((warning, index) => (
                        <li key={index}>{warning}</li>
                      ))}
                    </ul>
                  </div>
                </div>
              )}

              {validation?.related_records && (
                <div style={{ marginTop: '16px', padding: '16px', background: '#f7fafc', borderRadius: '8px' }}>
                  <strong>Related Records:</strong>
                  <ul style={{ marginTop: '8px', paddingLeft: '20px' }}>
                    <li>Payroll Profile: {validation.related_records.payroll_profile ? 'Yes' : 'No'}</li>
                    <li>Salary Records: {validation.related_records.salary_records}</li>
                    <li>Attendance Records: {validation.related_records.attendance_records}</li>
                    <li>Pending Salaries: {validation.related_records.pending_salaries}</li>
                    <li>Dividends: {validation.related_records.dividends}</li>
                  </ul>
                </div>
              )}

              {validation?.can_delete && validation?.related_records?.payroll_profile && (
                <div style={{ marginTop: '16px' }}>
                  <label style={{ display: 'flex', alignItems: 'center', gap: '8px', cursor: 'pointer' }}>
                    <input
                      type="checkbox"
                      checked={cascadeDelete}
                      onChange={(e) => setCascadeDelete(e.target.checked)}
                    />
                    Also delete related payroll records
                  </label>
                </div>
              )}
            </>
          )}
        </div>

        <div className="modal-footer">
          <button className="btn btn-secondary" onClick={onClose}>
            Cancel
          </button>
          <button
            className="btn btn-danger"
            onClick={handleConfirm}
            disabled={loading || (validation && !validation.can_delete)}
          >
            <FaTrash />
            Delete
          </button>
        </div>
      </div>
    </div>
  );
}

export default DeleteConfirmation;
